import React, { useState, useEffect } from "react";

import {
    modalBlurHandler,
    authAxios,
} from "../../static/js/util";
import { backendUrl } from "../../static/js/const";

const AddBoardModal = ({ setShowAddBoardModal, addBoard, project }) => {
    const [title, setTitle] = useState("");
    useEffect(modalBlurHandler(setShowAddBoardModal), []);

    const onSubmit = async (e) => {
        e.preventDefault();

        const formData = { name: title, isPublic: true };
        
        try {
            const { data } = await authAxios.post(
                `${backendUrl}/api/workspaces/${project}/boards`,
                formData
            );
            addBoard(data);
            setShowAddBoardModal(false);
        } catch (error) {
            console.error("Lỗi tạo bảng:", error);
        }
    };

    return (
        <div className="addboard-modal" style={{ width: "300px", background: "#fff", padding: "20px", borderRadius: "5px", position: "absolute", zIndex: 10 }}>
            <form className="addboard-modal__left" onSubmit={onSubmit} style={{ width: "100%" }}>
                <div
                    className="addboard-modal__title-block"
                    style={{ backgroundColor: "#0079bf", padding: "10px", borderRadius: "3px" }}
                >
                    <input
                        value={title}
                        onChange={(e) => {
                            setTitle(e.target.value);
                        }}
                        className="addboard-modal__title"
                        placeholder="Add board title"
                        style={{ width: "90%", background: "transparent", color: "white", border: "none", outline: "none" }}
                    />
                    <button
                        type="button"
                        className="addboard-modal__exit"
                        onClick={() => setShowAddBoardModal(false)}
                        style={{ background: "transparent", color: "white", border: "none", float: "right", cursor: "pointer" }}
                    >
                        <i className="fal fa-times"></i>
                    </button>
                </div>
                {title.trim() === "" ? (
                    <button
                        className="addboard-modal__create btn btn--disabled"
                        disabled
                        style={{ marginTop: "10px", width: "100%" }}
                    >
                        Create Board
                    </button>
                ) : (
                    <button
                        className="addboard-modal__create btn"
                        type="submit"
                        style={{ marginTop: "10px", width: "100%" }}
                    >
                        Create Board
                    </button>
                )}
            </form>
        </div>
    );
};

export default AddBoardModal;
